css:
/* Swiper Type 01 Styles */
.swiper-type-1 {
  width: 100%;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.08);
}

.card-slide {
  height: 220px;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  padding: 24px;
  position: relative;
  overflow: hidden;
  color: #ffffff;
}

.card-slide::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(180deg, rgba(0,0,0,0) 40%, rgba(0,0,0,0.6) 100%);
  z-index: 1;
}

.gradient-1 { background: linear-gradient(135deg, #ff2a5f 0%, #ff7e40 100%); }
.gradient-2 { background: linear-gradient(135deg, #00c6ff 0%, #0072ff 100%); }
.gradient-3 { background: linear-gradient(135deg, #f857a6 0%, #ff5858 100%); }

.swiper-controls {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 20px;
  background-color: #ffffff;
  border-top: 1px solid #f1f5f9;
}
